const channelsOpsThroughput = `-- name: ChannelsOpsThroughput :one
SELECT
    COALESCE(SUM(u.output_tokens_total), 0)::bigint AS output_tokens,
    COALESCE(SUM(
        CASE WHEN r.completed_at IS NOT NULL
             THEN EXTRACT(EPOCH FROM (r.completed_at - COALESCE(r.response_started_at, r.started_at))) END
    ), 0)::float8 AS generation_seconds
FROM request_records r
JOIN usage_records u ON u.request_record_id = r.id
WHERE r.status = 'succeeded'
  AND ($1::timestamptz IS NULL OR r.created_at >= $1::timestamptz)
  AND ($2::timestamptz IS NULL OR r.created_at < $2::timestamptz)
`

type ChannelsOpsThroughputParams struct {
	FromTime pgtype.Timestamptz
	ToTime   pgtype.Timestamptz
}

type ChannelsOpsThroughputRow struct {
	OutputTokens      int64
	GenerationSeconds float64
}

// ChannelsOpsThroughput 按最终成功渠道归因汇总输出 token 与生成耗时（供平台 TPS 卡）。
func (q *Queries) ChannelsOpsThroughput(ctx context.Context, arg ChannelsOpsThroughputParams) (ChannelsOpsThroughputRow, error) {
	row := q.db.QueryRow(ctx, channelsOpsThroughput, arg.FromTime, arg.ToTime)
	var i ChannelsOpsThroughputRow
	err := row.Scan(&i.OutputTokens, &i.GenerationSeconds)
	return i, err
}
